func (srv *Server) ServeTLS(ln net.Listener) error {
	if srv.isChild {
		process, err := os.FindProcess(os.Getppid())
		if err != nil {
			log.Println(err)
			return err
		}
		err = process.Signal(syscall.SIGTERM)
		if err != nil {
			return err
		}
	}

	go srv.handleSignals()
	return srv.internalServe(ln)
}
